Aqui está um programa Python simples que imprime todos os números primos entre 0 e 100:

```python
# criar uma função para verificar se um número é primo
def is_prime(num):
    if num > 1:
        # verificar os números primos
        for i in range(2, num):
            if (num % i) == 0:
                return False
        return True
    else:
        return False

# iterar de 0 a 100 e imprimir os números primos
for num in range(0, 101):
    if is_prime(num):
        print(num)
