def transformar_vogais(texto):
    vogais = ['a', 'e', 'i', 'o', 'u']
    novo_texto = ""
    for caractere in texto:
        if caractere in vogais:
            novo_texto += caractere.upper()
        else:
            novo_texto += caractere
    return novo_texto
